var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"마왕의 난세 아래 인류는 사라지고, 겨울만이 남는다.","JPN":"魔王の乱世のもとに人類は消え、冬だけが残る。","ENG":"Under the Demon Lord's age of chaos, humanity vanishes, leaving only winter behind.","TWN":"在魔王的亂世下，人類消失，只剩冬季。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"미래를 속삭이는 황금나무는 부러진 채 침묵한다.","JPN":"未来を囁く黄金の木は折れたまま沈黙する。","ENG":"The Golden Tree that whispers of the future stands broken, silent.","TWN":"輕聲述說未來的黃金樹，斷裂後陷入沉默。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그것이 세상의 끝이었다.","JPN":"それが世界の終わりだった。","ENG":"That was the end of the world.","TWN":"那便是世界的終結。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"분명 그러했을 텐데.","JPN":"そのはずだったが。","ENG":"It should have been.","TWN":"原本應該如此。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"모든 것을 얼어붙게 하는 겨울바람이 그치고, 땅에서 싹이 났다.","JPN":"すべてを凍らせる冬の風が止み、大地から芽が出た。","ENG":"The winter wind that freezes everything comes to a halt, and sprouts emerge from the earth.","TWN":"凍結一切的寒風靜止，土地萌芽。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"새로운 해가 뜨고, 새로운 생명이 움튼다.","JPN":"新しい日が昇り、新しい命が芽生える。","ENG":"A new sun rises, and new life begins to stir.","TWN":"新日升起，孕育著新生命。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"그 중심에는 황금나무를 감싸 안은 한 소녀가 있었다.","JPN":"その中心には黄金の木を抱いた一人の少女がいた。","ENG":"And at its center is a girl embracing the Golden Tree.","TWN":"在這中間，有個擁抱黃金樹的少女。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"...무슨 일이십니까?","JPN":"……どうされましたか？","ENG":"...What brings you here?","TWN":"……發生什麼事了？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"에클레시아를 만나고 싶어요.","JPN":"エクレシアに会いたいんです。","ENG":"I want to meet Ecclesia.","TWN":"我想見艾可露西亞。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"곧 돌아올 테니, 잠시 이곳에서 기다리시지요.","JPN":"すぐ戻りますので、しばらくここでお待ちください。","ENG":"She will be back soon, so please wait here for a while.","TWN":"她很快就回來，你先在這裡等她吧。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"에클레시아는 지금 자신이 가장 좋아하는 곳에서 기도 중입니다.","JPN":"エクレシアは今、自分が一番好きな場所で祈りを捧げております。","ENG":"Ecclesia is praying right now in the place she loves most.","TWN":"艾可露西亞現在在她最喜愛的地方祈禱。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어디에서요?","JPN":"どこでですか？","ENG":"Where?","TWN":"那在哪裡？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"낙원의 가장 양지 바른 자리. 황금나무의 언덕이랍니다.","JPN":"楽園で最も日当たりの良い場所。黄金の木の丘です。","ENG":"The sunniest place in the Promised Land. The hill of the Golden Tree.","TWN":"樂園最陽光充足的地方，黃金樹的小丘。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신이 에클레시아의 아버지... 맞죠?","JPN":"あなたがエクレシアのお父さん……ですよね？","ENG":"You are Ecclesia's father... aren't you?","TWN":"你是艾可露西亞的父親……對吧？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그 아이에 대해 얼마나 알고 있나요?","JPN":"あの子についてどこまで知っていますか？","ENG":"How much do you know about her?","TWN":"你對那孩子瞭解多少？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"당신이 가진 <color=#ffd34c>다른 존재</color>의 기억보다 많은 걸 알고 있지요.","JPN":"あなたの持つ<color=#ffd34c>他の存在</color>の記憶よりも多くのことを知っております。","ENG":"More than the memories of the <color=#ffd34c>other being</color> within you.","TWN":"我知道的比你對<color=#ffd34c>其他存在</color>的記憶還多。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...네퀴티아를 알고 있어?","JPN":"……ネキティアを知ってるの？","ENG":"...You know Nequitia?","TWN":"……你認識莉奎蒂亞？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"저는 많은 걸 알고 있습니다.","JPN":"私が知っていることはたくさんあります。","ENG":"I know many things.","TWN":"我知道很多事。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"당신 안에 두 사람의 운명이 묶여 있다는 것도-","JPN":"あなたの中で二人分の運命が絡み合っていることも……","ENG":"Including the fact that the fates of two people are bound within you...","TWN":"我也知道你體內交織著兩人的命運—"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그 둘이 서로를 받아들이지 못한 채 외면하고 있다는 사실도요.","JPN":"その二人がお互いを受け入れられないまま、目を背けているという事実もです。","ENG":"And that neither can accept the other, so both choose to look away.","TWN":"兩人無法接受彼此、互相迴避。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...그렇다면 우리가 어쩌다 여기에 오게 됐는지도 알아?","JPN":"……じゃあ、私たちがどうやってここに来たのかも知ってるの？","ENG":"...Then do you also know how we ended up here?","TWN":"……那你知道我們怎麼會來到這裡嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"외지인이 이곳에 당도하는 이유는 단 하나.","JPN":"よそ者がここにたどり着く理由はたった一つ。","ENG":"There is only one reason outsiders arrive here.","TWN":"外地人來到這裡，只有一個原因。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"낙원이 그러길 바랐기 때문입니다.","JPN":"楽園がそれを望んだからです。","ENG":"Because the Promised Land wished it so.","TWN":"樂園希望如此。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그러니, 당신도 낙원에서의 삶이 만족스러우셨으면 좋겠군요.","JPN":"ですから、あなたも楽園での生活に満足していただけたら幸いです。","ENG":"So I hope you, too, will find life in the Promised Land fulfilling.","TWN":"所以，希望你也可以滿意在樂園的生活。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"응, 간만의 기적 같은 평화를 만끽하고 있어.","JPN":"うん、久しぶりに奇跡のような平和を満喫してる。","ENG":"Yes, I'm enjoying a miracle-like peace I haven't felt in a long time.","TWN":"嗯，我很享受如奇蹟般的和平。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"무엇보다 엄마를 이렇게 다시 만날 수 있었다는 것에, 분에 넘치는 감사를 느껴.","JPN":"何よりこうやってお母さんにまた会えたことは、私にはもったいないくらいだよ。","ENG":"More than anything, I feel an undeserved gratitude for being able to see my mother again like this.","TWN":"最感激的是我能再次見到母親。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하지만 돌아가야 해. 언제까지고 기적을 꿈꾸고만 있을 순 없으니까.","JPN":"でも戻らないと。いつまでも奇跡を夢見ているわけにはいかないから。","ENG":"But I have to go back. I can't keep dreaming of miracles forever.","TWN":"但我還是得回去。我不能永遠沉溺於奇蹟中。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"낙원은 뜻이 있는 자의 길을 막지 않습니다.","JPN":"楽園は意志ある者の行く手を阻むことはありません。","ENG":"The Promised Land does not bar the way of those with resolve.","TWN":"樂園不會阻礙有志者的未來。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"하지만 그 아이를 끌어들이진 마십시오.","JPN":"ですが、あの子を巻き込まないでください。","ENG":"But do not drag that child into it.","TWN":"但別把那孩子牽扯進來。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"에클레시아를 어떻게 할 셈이야?","JPN":"エクレシアをどうするつもり？","ENG":"What are you planning to do with Ecclesia?","TWN":"你打算怎麼處理艾可露西亞？"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"아무것도요.","JPN":"どうもしません。","ENG":"Nothing.","TWN":"什麼也不做。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"아비 된 자로서, 오랜 여정에 지친 그 아이가 편히 쉬게 해주고 있을 뿐입니다.","JPN":"父として、長旅に疲れたあの子がゆっくり休めるようにしているだけです。","ENG":"As her father, I am only letting that child, weary from a long journey, rest in peace.","TWN":"作為父親，只想讓這個在漫長旅途中感到疲憊的孩子能好好休息。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};